const LEAD_SOURCE_OPTIONS = ["website", "phone", "walk-in", "referral", "other"];
const INTEREST_OPTIONS = ["high", "medium", "low"];
const STATUS_OPTIONS = ["new", "contacted", "qualified", "converted", "lost"];

function statusMeta(status) {
  if (status === "converted" || status === "qualified") return { label: status || "new", badge: "badge badgeGreen" };
  if (status === "contacted") return { label: "contacted", badge: "badge badgeOrange" };
  if (status === "lost") return { label: "lost", badge: "badge badgePink" };
  return { label: status || "new", badge: "badge badgeCyan" };
}

function interestMeta(level) {
  if (level === "high") return { label: "High", badge: "badge badgeGreen" };
  if (level === "medium") return { label: "Medium", badge: "badge badgeOrange" };
  if (level === "low") return { label: "Low", badge: "badge badgeCyan" };
  return { label: "Unassigned", badge: "badge" };
}

function SectionCard({ title, subtitle, children }) {
  return (
    <div className="card cardPad" style={{ display: "grid", gap: "18px" }}>
      <div>
        <div className="sectionTitle">{title}</div>
        <div className="sub">{subtitle}</div>
      </div>
      {children}
    </div>
  );
}

function SummaryTile({ label, value, inverse = false }) {
  return (
    <div
      style={{
        border: inverse ? "1px solid rgba(255,255,255,0.16)" : "1px solid var(--border)",
        borderRadius: "16px",
        padding: "16px",
        background: inverse ? "rgba(255,255,255,0.12)" : "rgba(255,255,255,0.72)",
        display: "grid",
        gap: "6px",
      }}
    >
      <div
        style={{
          fontSize: "12px",
          fontWeight: 700,
          letterSpacing: "0.06em",
          textTransform: "uppercase",
          color: inverse ? "rgba(255,255,255,0.74)" : "var(--text-muted)",
        }}
      >
        {label}
      </div>
      <div style={{ fontSize: "20px", fontWeight: 700, color: inverse ? "#fff" : "var(--text)" }}>{value}</div>
    </div>
  );
}

export default function LeadForm({
  title,
  subtitle,
  modeLabel,
  form,
  onChange,
  onSubmit,
  saving,
  submitLabel,
  onCancel,
  includeStatus = false,
}) {
  const status = statusMeta(form.status || "new");
  const interest = interestMeta(form.interest_level);

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">{title}</div>
          <div className="pageSub">{subtitle}</div>
        </div>
      </div>

      <div style={{ display: "grid", gap: "20px", maxWidth: "920px", margin: "0 auto" }}>
        <div
          className="card cardPad"
          style={{
            display: "grid",
            gap: "16px",
            background: "linear-gradient(135deg, rgba(12,58,87,0.96) 0%, rgba(17,73,109,0.95) 62%, rgba(141,187,1,0.92) 100%)",
            color: "#fff",
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", gap: "16px", alignItems: "center", flexWrap: "wrap" }}>
            <div>
              <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.14em", opacity: 0.72 }}>{modeLabel}</div>
              <div style={{ fontSize: "28px", fontWeight: 800, letterSpacing: "-0.04em", marginTop: "8px" }}>
                {form.name || "Lead profile"}
              </div>
              <div style={{ marginTop: "6px", opacity: 0.82 }}>{form.email || "Email pending"} • {form.contact_number || "Phone pending"}</div>
            </div>
            <span className={status.badge} style={{ background: "rgba(255,255,255,0.14)", color: "#fff", borderColor: "rgba(255,255,255,0.18)" }}>
              {status.label}
            </span>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: "14px" }}>
            <SummaryTile label="Source" value={form.lead_source || "Not selected"} inverse />
            <SummaryTile label="Interest" value={interest.label} inverse />
            <SummaryTile label="Status" value={status.label} inverse />
          </div>
        </div>

        <form onSubmit={onSubmit} style={{ display: "grid", gap: "20px" }}>
          <SectionCard title="Lead Identity" subtitle="Capture the customer details cleanly so the CRM stays reliable and easy for the team to scan.">
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "16px" }}>
              <div>
                <label className="label">Full Name</label>
                <input className="input" name="name" value={form.name} onChange={onChange} placeholder="Customer full name" required />
              </div>
              <div>
                <label className="label">Contact Number</label>
                <input className="input" name="contact_number" value={form.contact_number} onChange={onChange} placeholder="0771234567" required />
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label className="label">Email Address</label>
                <input className="input" type="email" name="email" value={form.email} onChange={onChange} placeholder="customer@email.com" required />
              </div>
            </div>
          </SectionCard>

          <SectionCard title="Lead Quality" subtitle="Set the source, interest level, and current stage so follow-up work stays aligned across staff.">
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "16px" }}>
              <div>
                <label className="label">Lead Source</label>
                <select className="select" name="lead_source" value={form.lead_source} onChange={onChange} required>
                  <option value="">Select source</option>
                  {LEAD_SOURCE_OPTIONS.map((source) => (
                    <option key={source} value={source}>
                      {source}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <label className="label">Interest Level</label>
                <select className="select" name="interest_level" value={form.interest_level} onChange={onChange}>
                  <option value="">Select interest</option>
                  {INTEREST_OPTIONS.map((level) => (
                    <option key={level} value={level}>
                      {level}
                    </option>
                  ))}
                </select>
              </div>

              {includeStatus && (
                <div>
                  <label className="label">Status</label>
                  <select className="select" name="status" value={form.status} onChange={onChange}>
                    <option value="">Select status</option>
                    {STATUS_OPTIONS.map((statusOption) => (
                      <option key={statusOption} value={statusOption}>
                        {statusOption}
                      </option>
                    ))}
                  </select>
                </div>
              )}
            </div>
          </SectionCard>

          <div style={{ display: "flex", justifyContent: "flex-end", gap: "12px", flexWrap: "wrap" }}>
            <button type="button" className="btn" onClick={onCancel} disabled={saving}>
              Cancel
            </button>
            <button type="submit" className="btn btnPrimary" disabled={saving}>
              {saving ? "Saving..." : submitLabel}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
